previewCss:
.darma-loader-uiverse-bubblegum-trio {
  display: flex;
  justify-content: center;
  align-items: center;
  height: 100%;
}

.darma-loader-uiverse-bubblegum-trio__bubble {
width: 20px;
height: 20px;
border-radius: 50%;
background-image: linear-gradient(to right, var(--loader-color, #ff6b81), var(--loader-secondary-color, #ff9a44));
margin: 0 5px;
animation: darma-loader-uiverse-bubblegum-trio-bubbleAnimation 1.5s ease-in-out infinite;
}

@keyframes darma-loader-uiverse-bubblegum-trio-bubbleAnimation {
0%,
100% {
transform: scale(1);
opacity: 1;
}
50% {
transform: scale(2);
opacity: 0.5;
}
}

